// Small folder glyph for the sidebar — outline symbol (user-authored).
// Drawn as fill + even-odd with currentColor, so it adapts to light / dark.
function navFolderGlyph() {
  return `<svg class="nav-glyph" viewBox="0 0 88.05 71.3" fill="currentColor" fill-rule="evenodd" aria-hidden="true">
    <path d="M12.7,71.05h64.06c6.93,0,11.04-4.1,11.04-12.3V19.49c0-8.2-4.15-12.26-12.45-12.26h-36.57c-2.39,0-3.96-.68-5.81-2.2l-2.44-1.95C27.98.98,25.88.25,22.17.25h-10.94C4.35.25.25,4.25.25,12.41v46.34c0,8.2,4.15,12.3,12.45,12.3ZM12.8,63.97c-3.52,0-5.52-1.86-5.52-5.57V12.75c0-3.61,1.95-5.47,5.47-5.47h7.57c2.39,0,3.96.68,5.81,2.2l2.44,1.95c2.49,2.05,4.64,2.83,8.35,2.83h38.33c3.52,0,5.52,1.9,5.52,5.62v38.57c0,3.66-2,5.52-5.52,5.52H12.8ZM12.51,26.67h63.04v-2.78c0-2.34-1.12-3.37-3.42-3.37H15.92c-2.25,0-3.42,1.03-3.42,3.37v2.78Z"/>
  </svg>`;
}

// Large folder icon (Overview grid)
function folderIcon() {
  return `<img class="icon-png" src="${ICONS.folder}" alt="" aria-hidden="true">`;
}

// Generic document icon (RTF / text)
function rtfIcon() {
  return `<svg viewBox="0 0 96 116" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
    <path d="M14 4 H64 L88 28 V104 Q88 112 80 112 H16 Q8 112 8 104 V12 Q8 4 16 4 Z"
      fill="#ffffff" stroke="#d2d2d2" stroke-width="2"/>
    <path d="M64 4 L88 28 H70 Q64 28 64 22 Z" fill="#e2e2e2"/>
    <g stroke="#c2c2c2" stroke-width="3" stroke-linecap="round">
      <line x1="22" y1="48" x2="74" y2="48"/>
      <line x1="22" y1="60" x2="74" y2="60"/>
      <line x1="22" y1="72" x2="74" y2="72"/>
      <line x1="22" y1="84" x2="58" y2="84"/>
    </g>
  </svg>`;
}

// PDF icon
function pdfIcon() {
  return `<svg viewBox="0 0 96 116" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
    <path d="M14 4 H64 L88 28 V104 Q88 112 80 112 H16 Q8 112 8 104 V12 Q8 4 16 4 Z"
      fill="#ffffff" stroke="#d2d2d2" stroke-width="2"/>
    <path d="M64 4 L88 28 H70 Q64 28 64 22 Z" fill="#e2e2e2"/>
    <rect x="20" y="74" width="56" height="26" rx="4" fill="#EB5757"/>
    <text x="48" y="92" text-anchor="middle" font-family="-apple-system, sans-serif"
      font-size="15" font-weight="700" fill="#ffffff">PDF</text>
  </svg>`;
}

// ファイルアイコン: file.icon があれば画像、なければ type 別の既定 SVG
function fileIcon(file) {
  if (file.icon) return `<img class="icon-png" src="${file.icon}" alt="" aria-hidden="true">`;
  return file.type === "pdf" ? pdfIcon() : rtfIcon();
}

// macOS Finder tag colors. A folder's marker is a name ("blue") or a raw hex.
const MARKERS = {
  red:    "#FF5B56",
  orange: "#FA9E36",
  yellow: "#F7CE46",
  green:  "#62C554",
  blue:   "#2E9BFF",
  purple: "#C26FE3",
  gray:   "#A0A0A5",
  grey:   "#A0A0A5",
};
function markerColor(v) {
  if (!v) return null;
  return MARKERS[String(v).toLowerCase()] || v;   // name → hex, else pass a hex through
}
function dotSpan(v) {
  const c = markerColor(v);
  return c ? `<span class="dot" style="background:${c}"></span>` : "";
}

